    /// <summary>
    /// Backward-compatible training entry point.
    /// </summary>
    public static void Train(
        string outputModelPath,
        string inputDataFilePath = RetrainFilePath,
        char separatorChar = RetrainSeparatorChar,
        bool hasHeader = RetrainHasHeader,
        bool allowQuoting = RetrainAllowQuoting)
    {
        _ = separatorChar;
        _ = hasHeader;
        _ = allowQuoting;

        TrainWithOptions(new TrainingOptions
        {
            DataPath = inputDataFilePath,
            ModelOutputPath = outputModelPath,
            Trainer = "lbfgs",
